// Domain
data class FeedItem(val id: String, val title: String, val updatedAt: Long, val isLocalOnly: Boolean = false)

interface FeedRepository {
  fun observePage(): Flow<List<FeedItem>>
  suspend fun refresh(): Result<Unit>
  suspend fun loadMore(beforeId: String?)
}

// Implementation sketch
class FeedRepositoryImpl(
  private val dao: FeedDao,
  private val api: FeedApi,
  private val outbox: OutboxDao,
  private val io: CoroutineDispatcher
) : FeedRepository {

  override fun observePage(): Flow<List<FeedItem>> = dao.observe()
    .map { rows -> rows.map { it.toDomain() } }

  override suspend fun refresh(): Result<Unit> = withContext(io) {
    runCatching {
      val latest = dao.maxUpdatedAt()
      val response = api.fetch(sinceUpdatedAt = latest)
      dao.upsertAll(response.items.map { it.toEntity() })
    }
  }

  override suspend fun loadMore(beforeId: String?) = withContext(io) {
    val response = api.fetch(beforeId = beforeId, limit = 20)
    dao.upsertAll(response.items.map { it.toEntity() })
    Unit
  }
}

