// Optimistic write pattern
suspend fun likeItem(id: String) = withContext(io) {
  dao.markLiked(id, true)                           // immediate UI flip
  outbox.add(OutboxOp.Like(id))                     // queue server write
  scheduleSyncWorker()                              // best-effort retry-with-backoff
}

// Compose pagination — manual but explicit
@Composable
fun FeedScreen(vm: FeedViewModel = hiltViewModel()) {
  val items by vm.items.collectAsStateWithLifecycle()
  val listState = rememberLazyListState()

  LaunchedEffect(listState, items.size) {
    snapshotFlow { listState.layoutInfo.visibleItemsInfo.lastOrNull()?.index ?: -1 }
      .distinctUntilChanged()
      .collect { lastIndex ->
        if (lastIndex >= items.size - 5) vm.loadMore()
      }
  }

  LazyColumn(state = listState) {
    items(items, key = { it.id }) { Row(it) }
    item { FooterSpinner(visible = vm.isLoadingMore) }
  }
}

class FeedViewModel(private val repo: FeedRepository) : ViewModel() {
  val items: StateFlow<List<FeedItem>> = repo.observePage().stateIn(
    viewModelScope, SharingStarted.WhileSubscribed(5_000), emptyList()
  )
  var isLoadingMore by mutableStateOf(false)
  private var lastSeenId: String? = null

  fun loadMore() = viewModelScope.launch {
    if (isLoadingMore) return@launch
    isLoadingMore = true
    runCatching { repo.loadMore(beforeId = lastSeenId) }
    isLoadingMore = false
  }
}

