// Sending a message — optimistic + outbox
suspend fun sendMessage(chatId: String, body: String) {
  val clientId = UUID.randomUUID().toString()
  val now = System.currentTimeMillis()
  val local = MessageEntity(
    id = clientId, clientId = clientId, chatId = chatId,
    body = body, createdAt = now, state = MessageState.SENDING
  )
  dao.upsert(local)
  outbox.add(OutboxOp.SendMessage(clientId, chatId, body))
  syncScheduler.kick()
}

// Outbox worker
suspend fun drainOutbox() {
  for (op in outbox.dequeueBatch(20)) {
    when (op) {
      is OutboxOp.SendMessage -> try {
        val server = api.send(op.chatId, op.clientId, op.body)
        dao.replaceClientWithServer(
          clientId = op.clientId,
          serverId = server.id,
          serverCreatedAt = server.createdAt
        )
        outbox.remove(op)
      } catch (e: IOException) {
        dao.markFailed(op.clientId)
        // backoff handled by WorkManager / BGTask
      }
    }
  }
}

