// Flag interface — typed, testable
interface FeatureFlags {
  val checkoutV2Enabled: Boolean
  val newSearchEnabled: Boolean
  val paywallVariant: PaywallVariant
}

// Production impl — backed by Remote Config + local override store
class RemoteFlags(
  private val rc: RemoteConfig,
  private val overrides: FlagOverrideStore
) : FeatureFlags {
  override val checkoutV2Enabled get() =
    overrides.boolOrNull("checkout_v2") ?: rc.boolean("checkout_v2")
  override val newSearchEnabled get() =
    overrides.boolOrNull("new_search") ?: rc.boolean("new_search")
  override val paywallVariant get() = PaywallVariant.parse(rc.string("paywall_variant"))
}

// Dependency wiring — pick implementation
@Module
@InstallIn(SingletonComponent::class)
object CheckoutModule {
  @Provides
  fun provideCheckout(flags: FeatureFlags, v1: Lazy<CheckoutV1>, v2: Lazy<CheckoutV2>): Checkout =
    if (flags.checkoutV2Enabled) v2.get() else v1.get()
}

