// Internal interface
interface AnalyticsClient {
  fun track(event: AnalyticsEvent)
  fun identify(userId: String?)
  fun setProperty(key: String, value: Any?)
}

sealed class AnalyticsEvent(val name: String, val properties: Map<String, Any?>) {
  class ScreenViewed(screen: String) : AnalyticsEvent("screen_viewed", mapOf("screen" to screen))
  class CheckoutCompleted(orderId: String, total: Money) :
    AnalyticsEvent("checkout_completed", mapOf("order_id" to orderId, "total_cents" to total.cents))
  class FeatureFlagExposure(flag: String, variant: String) :
    AnalyticsEvent("flag_exposure", mapOf("flag" to flag, "variant" to variant))
}

// Multi-sink dispatcher — sends to Mixpanel + Sentry breadcrumbs + offline buffer
class MultiplexAnalytics(
  private val sinks: List<AnalyticsSink>,
  private val buffer: AnalyticsBuffer
) : AnalyticsClient {
  override fun track(event: AnalyticsEvent) {
    sinks.forEach { runCatching { it.track(event) } }
    buffer.append(event)
  }
  override fun identify(userId: String?) { sinks.forEach { it.identify(userId) } }
  override fun setProperty(key: String, value: Any?) { sinks.forEach { it.setProperty(key, value) } }
}

