// Performance — instrument key spans
val transaction = Sentry.startTransaction("feed_load", "task")
val span = transaction.startChild("network.fetch")
try {
  api.feed()
  span.finish(SpanStatus.OK)
} catch (e: Throwable) {
  span.finish(SpanStatus.INTERNAL_ERROR)
  throw e
} finally {
  transaction.finish()
}

// Telemetry stream — Flow with buffer + chunking
fun telemetryFlow(): Flow<List<Sample>> = flow {
  socket.messages
    .map { it.toSample() }
    .buffer(capacity = 256, onBufferOverflow = BufferOverflow.DROP_OLDEST)
    .chunked(durationMs = 100)         // accumulate every 100ms
    .collect { batch -> emit(batch) }
}

// Compose UI — display rolling window
@Composable
fun TelemetryChart(stream: Flow<List<Sample>>) {
  var window by remember { mutableStateOf<List<Sample>>(emptyList()) }
  LaunchedEffect(stream) {
    stream.collect { batch ->
      window = (window + batch).takeLast(500)
    }
  }
  LineChart(samples = window)
}

// Resume after disconnect
suspend fun connectWithResume(lastSeq: Long?): WebSocketSession {
  while (true) {
    try {
      return ws.connect("/stream?from=\${lastSeq ?: 0}")
    } catch (e: IOException) {
      val backoff = (Random.nextLong(500, 1500) * 2.0.pow(retries.toDouble())).toLong()
      delay(backoff.coerceAtMost(30_000))
      retries++
    }
  }
}

// Persist progress (crash-safe resume)
suspend fun onBatch(batch: List<Sample>) {
  db.transaction {
    samplesDao.insertAll(batch.map { it.toEntity() })
    metaDao.setLastSeq(batch.last().seq)
  }
}
